/**
 * Storybook reference-data adapter.
 *
 * The single source of truth for the formats and tools shown in these stories
 * is `@neokapi/reference-data` (generated by `scripts/gen-refs`). That package
 * exports two `ReferenceDataset`s вЂ” `formats` and `tools` вЂ” each carrying an
 * `entries: ReferenceEntry[]` array with schema, docs, and presets.
 *
 * The stories were originally written against ad-hoc JSON fixtures produced by
 * `scripts/gen-storybook-fixtures.sh`. This module derives вЂ” from
 * reference-data вЂ” the exact shapes those stories expect, so the per-story
 * change is just swapping the import source. Nothing here invents data; every
 * field comes straight from a `ReferenceEntry`.
 *
 * Source naming: reference-data uses `source: "built-in" | "okapi"`. The
 * legacy fixtures used `"built-in" | "okapi-bridge"` (and the schema-story
 * helpers a `"builtIn" | "bridge"` discriminator). The helpers below translate
 * between them so the existing story code keeps working unchanged.
 */
import { formats as formatsDataset, tools as toolsDataset } from "@neokapi/reference-data";
import type { ReferenceEntry } from "@neokapi/reference-data";
import type { ComponentSchema } from "@neokapi/ui-primitives";

const formatEntries = formatsDataset.entries;
const toolEntries = toolsDataset.entries;

// в”Ђв”Ђ Schema entries в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
//
// The old `format-schemas.json` / `tool-schemas.json` fixtures stored each
// schema with two extra keys, `x-name` and `x-source`, and split them into
// `{ builtIn, bridge, all }`. We reproduce that shape from each entry's
// `schema`, stamping the same two keys back on so `findIn(...)` style lookups
// in `schema-story.tsx` and the browsers keep working.

/** A schema augmented with the `x-name` / `x-source` keys the stories key off. */
export type SchemaEntry = ComponentSchema & {
  "x-name": string;
  "x-source": string;
};

/** The `{ builtIn, bridge, all }` bucket shape the schema fixtures used. */
export interface SchemaBuckets {
  builtIn: SchemaEntry[];
  bridge: SchemaEntry[];
  all: SchemaEntry[];
}

function toSchemaEntry(entry: ReferenceEntry): SchemaEntry | null {
  if (!entry.schema) return null;
  return {
    ...(entry.schema as ComponentSchema),
    "x-name": entry.id,
    "x-source": entry.source === "okapi" ? "okapi-bridge" : "built-in",
  };
}

function schemaBuckets(entries: ReferenceEntry[]): SchemaBuckets {
  const builtIn: SchemaEntry[] = [];
  const bridge: SchemaEntry[] = [];
  for (const entry of entries) {
    const schema = toSchemaEntry(entry);
    if (!schema) continue;
    if (entry.source === "okapi") bridge.push(schema);
    else builtIn.push(schema);
  }
  return { builtIn, bridge, all: [...builtIn, ...bridge] };
}

/** Replaces `fixtures/format-schemas.json`. */
export const formatSchemas: SchemaBuckets = schemaBuckets(formatEntries);

/** Replaces `fixtures/tool-schemas.json`. */
export const toolSchemas: SchemaBuckets = schemaBuckets(toolEntries);

// в”Ђв”Ђ Format / tool list metadata в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
//
// The old `format-list.json` / `tool-list.json` fixtures carried metadata-only
// rows (no full schema). They split into `{ builtIn, bridge }` using snake_case
// field names that match the app's `FormatInfo` / `ToolInfo` API types.

export interface FormatListEntry {
  name: string;
  display_name: string;
  source: string;
  extensions: string[];
  mime_types: string[];
  has_reader?: boolean;
  has_writer?: boolean;
}

export interface ToolListEntry {
  name: string;
  display_name?: string;
  description: string;
  category: string;
  source: string;
  has_schema?: boolean;
  inputs?: string[];
  tags?: string[];
}

function toFormatListEntry(entry: ReferenceEntry): FormatListEntry {
  return {
    name: entry.id,
    display_name: entry.displayName,
    source: entry.source === "okapi" ? "okapi-bridge" : "built-in",
    extensions: entry.extensions ?? [],
    mime_types: entry.mimeTypes ?? [],
    has_reader: entry.hasReader,
    has_writer: entry.hasWriter,
  };
}

function toToolListEntry(entry: ReferenceEntry): ToolListEntry {
  return {
    name: entry.id,
    display_name: entry.displayName,
    description: entry.description ?? "",
    category: entry.category ?? "other",
    source: entry.source === "okapi" ? "okapi-bridge" : "built-in",
    has_schema: !!entry.schema,
    inputs: entry.inputs ?? [],
    tags: entry.tags ?? [],
  };
}

/** Replaces `fixtures/format-list.json`. */
export const formatList: { builtIn: FormatListEntry[]; bridge: FormatListEntry[] } = {
  builtIn: formatEntries.filter((e) => e.source !== "okapi").map(toFormatListEntry),
  bridge: formatEntries.filter((e) => e.source === "okapi").map(toFormatListEntry),
};

/** Replaces `fixtures/tool-list.json`. */
export const toolList: { builtIn: ToolListEntry[]; bridge: ToolListEntry[] } = {
  builtIn: toolEntries.filter((e) => e.source !== "okapi").map(toToolListEntry),
  bridge: toolEntries.filter((e) => e.source === "okapi").map(toToolListEntry),
};

// в”Ђв”Ђ Presets в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
//
// The old `presets.json` was a `{ formatId: { presetId: params } }` map built
// only from bridge formats. Each reference-data entry carries the same map in
// `entry.presets`, so we just collect the non-empty ones.

export type PresetsByFormat = Record<string, Record<string, Record<string, unknown> | null>>;

function collectPresets(entries: ReferenceEntry[]): PresetsByFormat {
  const out: PresetsByFormat = {};
  for (const entry of entries) {
    if (entry.presets && Object.keys(entry.presets).length > 0) {
      out[entry.id] = entry.presets as Record<string, Record<string, unknown> | null>;
    }
  }
  return out;
}

/** Replaces `fixtures/presets.json` (format presets keyed by format id). */
export const presets: PresetsByFormat = collectPresets(formatEntries);

// в”Ђв”Ђ Plugin docs в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
//
// The old `plugin-docs.json` had `{ filters: { id: FilterDoc }, steps: { id:
// StepDoc } }`. Reference-data carries the same content per entry under
// `entry.doc` (a `ReferenceDoc`), so we reshape: okapi *formats* with a doc go
// under `filters`, okapi *tools* with a doc go under `steps`. The doc field
// names line up almost exactly; we add `filterName`/`stepId`/`filterId` from
// the entry's `displayName`/`id`.

interface DocBase {
  filterName: string;
  overview: string;
  wikiUrl?: string;
  parameters?: Record<string, unknown>;
  limitations?: string[];
  processingNotes?: string[];
  examples?: unknown[];
}

interface FilterDocShape extends DocBase {
  filterId?: string;
}

interface StepDocShape extends DocBase {
  stepId?: string;
}

export interface PluginDocsShape {
  generatedAt?: string;
  wikiBaseUrl?: string;
  filters: Record<string, FilterDocShape>;
  steps: Record<string, StepDocShape>;
}

function docBase(entry: ReferenceEntry): DocBase {
  const doc = entry.doc!;
  return {
    filterName: entry.displayName,
    overview: doc.overview ?? "",
    wikiUrl: doc.wikiUrl,
    parameters: doc.parameters,
    limitations: doc.limitations,
    processingNotes: doc.processingNotes,
    examples: doc.examples,
  };
}

function buildPluginDocs(): PluginDocsShape {
  const filters: Record<string, FilterDocShape> = {};
  const steps: Record<string, StepDocShape> = {};
  for (const entry of formatEntries) {
    if (entry.source === "okapi" && entry.doc) {
      filters[entry.id] = { ...docBase(entry), filterId: entry.id };
    }
  }
  for (const entry of toolEntries) {
    if (entry.source === "okapi" && entry.doc) {
      steps[entry.id] = { ...docBase(entry), stepId: entry.id };
    }
  }
  return {
    generatedAt: formatsDataset.generatedAt,
    wikiBaseUrl: "https://okapiframework.org/wiki/",
    filters,
    steps,
  };
}

/** Replaces `fixtures/plugin-docs.json`. */
export const pluginDocs: PluginDocsShape = buildPluginDocs();

// в”Ђв”Ђ Okapi filter schema list в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
//
// The old `okapi-metadata.json` had `{ filters: ComponentSchema[], steps:
// ComponentSchema[] }` вЂ” the raw okapi-bridge schemas (with `$id`, `$schema`,
// `$defs`, etc.). Reference-data preserves those schemas verbatim on each
// okapi-source entry, so the filter/step schema arrays are just the okapi
// entries' schemas.

export interface OkapiMetadataShape {
  filters: ComponentSchema[];
  steps: ComponentSchema[];
}

/** Replaces `fixtures/okapi-metadata.json`. */
export const okapiMetadata: OkapiMetadataShape = {
  filters: formatEntries
    .filter((e) => e.source === "okapi" && e.schema)
    .map((e) => e.schema as ComponentSchema),
  steps: toolEntries
    .filter((e) => e.source === "okapi" && e.schema)
    .map((e) => e.schema as ComponentSchema),
};

// в”Ђв”Ђ Tools metadata (FlowsPage / ToolRunnerPage) в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
//
// The old `tools-metadata.json` was a flat `ToolInfo[]` of built-in tools.
// Reproduce it from the built-in tool entries using the snake_case `ToolInfo`
// field names the app types expect.

export interface ToolMetadataEntry {
  name: string;
  display_name?: string;
  description: string;
  category: string;
  has_schema: boolean;
  inputs: string[];
  outputs?: string[];
  tags: string[];
  requires: string[];
}

function toToolMetadata(entry: ReferenceEntry): ToolMetadataEntry {
  return {
    name: entry.id,
    display_name: entry.displayName,
    description: entry.description ?? "",
    category: entry.category ?? "other",
    has_schema: !!entry.schema,
    inputs: entry.inputs ?? [],
    outputs: entry.outputs ?? undefined,
    tags: entry.tags ?? [],
    requires: entry.requires ?? [],
  };
}

/** Replaces `fixtures/tools-metadata.json` (built-in tools, flat list). */
export const toolsMetadata: ToolMetadataEntry[] = toolEntries
  .filter((e) => e.source !== "okapi")
  .map(toToolMetadata);
